/**
 * @name Path traversal in StaticHandlerImpl - taint flow from request path to file operation
 * @description Tracks taint from request URI/path to file operations in StaticHandlerImpl
 * @kind path-problem
 * @problem.severity error
 * @id java/static-handler-taint-path
 * @tags security
 *       external/cwe/cwe-022
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module StaticHandlerPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: request path/URI from RoutingContext
    exists(MethodCall mc |
      mc.getMethod().hasName("path") and
      mc.getMethod().getDeclaringType().hasQualifiedName("io.vertx.ext.web", "RoutingContext") and
      source.asExpr() = mc
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("normalizedPath") and
      mc.getMethod().getDeclaringType().hasQualifiedName("io.vertx.ext.web", "RoutingContext") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: sendFile or similar operations
    exists(MethodCall mc |
      mc.getMethod().hasName("sendFile") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // Paths.get
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module StaticHandlerPathFlow = TaintTracking::Global<StaticHandlerPathConfig>;
import StaticHandlerPathFlow::PathGraph

from StaticHandlerPathFlow::PathNode source, StaticHandlerPathFlow::PathNode sink
where StaticHandlerPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path from HTTP request flows to file operation without proper sanitization: $@", source.getNode(), "user-controlled path"

/**
 * @name Path traversal in StaticHandlerImpl via taint flow
 * @description Taint tracking from HTTP request path to file system operation in StaticHandlerImpl
 * @kind path-problem
 * @problem.severity error
 * @id java/static-handler-path-traversal-taint
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // path() or normalizedPath() on HttpServerRequest
    exists(MethodCall mc |
      (mc.getMethod().hasName("path") or mc.getMethod().hasName("normalizedPath")) and
      mc.getMethod().getDeclaringType().hasQualifiedName("io.vertx.core.http", "HttpServerRequest") and
      source.asExpr() = mc
    )
    or
    // normalizePath() result
    exists(MethodCall mc |
      mc.getMethod().hasName("normalizePath") and
      mc.getMethod().getDeclaringType().hasQualifiedName("io.vertx.ext.web.impl", "Utils") and
      source.asExpr() = mc
    )
    or
    // removeDots result
    exists(MethodCall mc |
      mc.getMethod().hasName("removeDots") and
      mc.getMethod().getDeclaringType().hasQualifiedName("io.vertx.ext.web.impl", "Utils") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // sendFile call in RoutingContext / HttpServerResponse
    exists(MethodCall mc |
      (mc.getMethod().hasName("sendFile") or mc.getMethod().hasName("sendStatic")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // getFile call in StaticHandlerImpl
    exists(MethodCall mc |
      mc.getMethod().hasName("getFile") and
      mc.getMethod().getDeclaringType().hasQualifiedName("io.vertx.ext.web.handler.impl", "StaticHandlerImpl") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: HTTP request path flows to file operation without sufficient validation $@.", source.getNode(), "user-controlled path"
